  return useQuery({
    queryKey: crmKeys.fireflies(),
    queryFn: async () => {
      const res = await fetch(FIREFLIES_HEALTH_URL)
      return res.ok
    },
    staleTime: 60_000,
    gcTime: 10 * 60_000,
    refetchInterval: 120_000,
    retry: 1,
  })
}

